.mrg-code {
  background: var(--mrg-semantic-color-background-surface-sunken);
  border-radius: var(--mrg-semantic-radius-status);
  color: var(--mrg-semantic-color-foreground-primary);
  font-family: var(--mrg-semantic-font-family-machine);
  font-size: var(--mrg-semantic-font-size-code);
  line-height: var(--mrg-semantic-font-line-height-code);
  padding-block: var(--mrg-semantic-space-inline-xs);
  padding-inline: var(--mrg-semantic-space-inline-sm);
  user-select: text;
}
.mrg-code[data-wrap="true"] {
  overflow-wrap: anywhere;
  white-space: break-spaces;
}
.mrg-code[data-wrap="false"] {
  display: inline-block;
  max-inline-size: 100%;
  overflow-x: auto;
  white-space: pre;
}
@media (forced-colors: active) {
  .mrg-code {
    background: Canvas;
    border: 1px solid CanvasText;
    color: CanvasText;
  }
}

import { forwardRef, type HTMLAttributes } from "react";

import "./code.css";

export interface CodeProps extends HTMLAttributes<HTMLElement> {
  readonly wrap?: boolean;
}

export const Code = forwardRef<HTMLElement, CodeProps>(function Code(
  { className, wrap = true, ...nativeProps },
  forwardedRef,
) {
  return (
    <code
      {...nativeProps}
      ref={forwardedRef}
      className={
        className === undefined || className.trim().length === 0
          ? "mrg-code"
          : `mrg-code ${className}`
      }
      data-slot="code"
      data-wrap={wrap ? "true" : "false"}
    />
  );
});

Code.displayName = "Code";
